using Ledgerly.Domain.Entities; using Ledgerly.Domain.Enums; using Ledgerly.Domain.ValueObjects; namespace Ledgerly.Domain.Tests; public class InvoiceTests { static readonly CurrencyCode Usd=new("USD"); static readonly Guid Org=Guid.NewGuid(),Cust=Guid.NewGuid(),Inc=Guid.NewGuid(),Ar=Guid.NewGuid(),Tax=Guid.NewGuid(); [Fact] public void Send_sets_sent(){ var i=new Invoice(Org,Cust,"INV-1",new DateOnly(2026,3,1),new DateOnly(2026,3,31),Usd,Inc,Ar); i.AddLine("X",1m,new Money(100m,Usd),Tax,new Money(0m,Usd)); i.Send(new Dictionary<Guid,decimal>{{Tax,0.1m}}); Assert.Equal(InvoiceStatus.Sent,i.Status); Assert.Equal(110m,i.TotalAmount.Amount);} [Fact] public void RecordPayment_paid(){ var i=new Invoice(Org,Cust,"INV-2",new DateOnly(2026,3,1),new DateOnly(2026,3,31),Usd,Inc,Ar); i.AddLine("X",1m,new Money(100m,Usd),null,new Money(0m,Usd)); i.Send(new Dictionary<Guid,decimal>()); i.RecordPayment(new Money(100m,Usd)); Assert.Equal(InvoiceStatus.Paid,i.Status);} }
